3	import (
4		"fmt"
5		"strings"
6	
7		"github.com/DocumentDrivenDX/ddx/internal/bead"
8	)
9	
10	// ExecutionIntentSource identifies where a routing intent came from.
11	type ExecutionIntentSource string
12	
13	const (
14		ExecutionIntentSourceDefault     ExecutionIntentSource = "default"
15		ExecutionIntentSourceBeadHint    ExecutionIntentSource = "bead_hint"
16		ExecutionIntentSourceReadiness   ExecutionIntentSource = "readiness"
17		ExecutionIntentSourceProject     ExecutionIntentSource = "project_config"
18		ExecutionIntentSourceCLIPassthru ExecutionIntentSource = "cli"
19	)
20	
21	// ExecutionHint captures the request-level routing intent DDx can explain
22	// without binding to a concrete harness/provider/model route.
23	type ExecutionHint struct {
24		Source              ExecutionIntentSource
25		EstimatedDifficulty EstimatedDifficulty
26		InferredPowerClass  PowerClass
27		RejectedRoutePins   []string
28	}
29	
30	type ExecutionHintInput struct {
31		Bead                         *bead.Bead
32		ReadinessEstimatedDifficulty string
33		ExplicitRouting              bool
34		ProjectRouting               bool
35	}
36	
37	// ExecutionHintFinding is a single lint finding emitted when bead metadata
38	// carries a durable route pin.
39	type ExecutionHintFinding struct {
40		Field   string `json:"field"`
41		Value   string `json:"value,omitempty"`
42		Message string `json:"message"`
43	}
44	
45	// ParseExecutionHint derives the bead's abstract execution intent from its
46	// durable metadata. Only triage.estimated_difficulty is recognized as a
47	// bead-level difficulty hint; labels such as kind, priority, or power do not
48	// affect routing intent.
49	func ParseExecutionHint(b *bead.Bead) ExecutionHint {
50		return ResolveExecutionHint(ExecutionHintInput{Bead: b})
51	}
52	
53	// ResolveExecutionHint applies the TD-037 precedence for execution intent:
54	// explicit CLI routing first, project routing second, durable bead difficulty
55	// third, transient readiness difficulty fourth, and the ordinary standard route
56	// otherwise. Concrete route pins are lint-only diagnostics and never influence
57	// the inferred power class.
58	func ResolveExecutionHint(input ExecutionHintInput) ExecutionHint {
59		hint := ExecutionHint{
60			Source:             ExecutionIntentSourceDefault,
61			InferredPowerClass: PowerStandard,
62		}
63		b := input.Bead
64		switch {
65		case input.ExplicitRouting:
66			hint.Source = ExecutionIntentSourceCLIPassthru
67			hint.InferredPowerClass = ""
68		case input.ProjectRouting:
69			hint.Source = ExecutionIntentSourceProject
70			hint.InferredPowerClass = ""
71		default:
72			hint = resolveDifficultyExecutionHint(b, input.ReadinessEstimatedDifficulty)
73		}
74	
75		if b == nil {
76			return hint
77		}
78	
79		for _, raw := range b.Labels {
80			if pin, ok := parseDurableRoutePinLabel(raw); ok {
81				hint.RejectedRoutePins = append(hint.RejectedRoutePins, pin)
82			}
83		}
84		if len(b.Extra) > 0 {
85			for k, v := range b.Extra {
86				if pin, ok := parseDurableRoutePinField(k, v); ok {
87					hint.RejectedRoutePins = append(hint.RejectedRoutePins, pin)
88				}
89			}
90		}
91	
92		return hint
93	}
94	
95	func resolveDifficultyExecutionHint(b *bead.Bead, readinessEstimatedDifficulty string) ExecutionHint {
96		hint := ExecutionHint{
97			Source:             ExecutionIntentSourceDefault,
98			InferredPowerClass: PowerStandard,
99		}
100		if difficulty, ok := BeadEstimatedDifficulty(b); ok {
101			hint.Source = ExecutionIntentSourceBeadHint
102			hint.EstimatedDifficulty = difficulty
103			hint.InferredPowerClass = PowerClassForEstimatedDifficulty(difficulty)
104		} else if difficulty, ok := parseEstimatedDifficulty(readinessEstimatedDifficulty); ok {
105			hint.Source = ExecutionIntentSourceReadiness
106			hint.EstimatedDifficulty = difficulty
107			hint.InferredPowerClass = PowerClassForEstimatedDifficulty(difficulty)
108		}
109		return hint
110	}
111	
112	// LintExecutionHints returns durable-routing findings for the bead. The lint
113	// surface is intentionally narrow: it rejects durable model/provider/harness
114	// pins that should stay on one-off CLI flags.
115	func LintExecutionHints(b *bead.Bead) []ExecutionHintFinding {
116		if b == nil {
117			return nil
118		}
119		hint := ParseExecutionHint(b)
120		findings := make([]ExecutionHintFinding, 0, len(hint.RejectedRoutePins))
121	
122		for _, pin := range hint.RejectedRoutePins {
123			findings = append(findings, durableRoutePinFinding(b.ID, pin))
124		}
125	
126		return findings
127	}
128	
129	func parseDurableRoutePinLabel(raw string) (string, bool) {
130		l := strings.ToLower(strings.TrimSpace(raw))
131		if l == "" {
132			return "", false
133		}
134		switch {
135		case strings.HasPrefix(l, "harness:"),
136			strings.HasPrefix(l, "provider:"),
137			strings.HasPrefix(l, "model:"):
138			if idx := strings.IndexByte(l, ':'); idx > 0 {
139				return l[:idx], true
140			}
141			return l, true
142		default:
143			return "", false
144		}
145	}
146	
147	func parseDurableRoutePinField(key string, value any) (string, bool) {
148		lower := strings.ToLower(strings.TrimSpace(key))
149		switch lower {
150		case "harness", "agent-harness", "execution-harness", "try-harness",
151			"provider", "agent-provider", "execution-provider", "try-provider",
152			"model", "agent-model", "execution-model", "try-model",
153			"model-ref", "agent-model-ref", "execution-model-ref", "try-model-ref":
154			return renderDurableRoutePin(lower, value), true
155		default:
156			return "", false
157		}
158	}
159	
160	func renderDurableRoutePin(key string, value any) string {
161		if value == nil {
162			return key
163		}
164		if s, ok := value.(string); ok && strings.TrimSpace(s) != "" {
165			return fmt.Sprintf("%s=%s", key, s)
166		}
167		return key
168	}
169	
170	func durableRoutePinFinding(beadID, pin string) ExecutionHintFinding {
171		field := pin
172		if idx := strings.IndexByte(pin, '='); idx > 0 {
173			field = pin[:idx]
174		}
175		var message string
176		switch {
177		case strings.Contains(field, "harness"):
178			message = fmt.Sprintf("bead metadata contains %s; durable harness pins are not allowed. Use ddx try %s --harness ... for one-off debugging.", pin, beadID)
179		case strings.Contains(field, "provider"):
180			message = fmt.Sprintf("bead metadata contains %s; durable provider pins are not allowed. Use ddx try %s --provider ... for one-off debugging.", pin, beadID)
181		case strings.Contains(field, "model"):
182			message = fmt.Sprintf("bead metadata contains %s; durable model pins are not allowed. Use ddx try %s --model ... for one-off debugging.", pin, beadID)
183		default:
184			message = fmt.Sprintf("bead metadata contains %s; durable route pins are not allowed.", pin)
185		}
186		return ExecutionHintFinding{
187			Field:   field,
188			Value:   pin,
189			Message: message,
190		}
191	}
