package agent

import (
	"strings"
	"sync"
	"time"
)

// OutcomeClass is a typed attempt-outcome class from the shared FEAT-004
// failure-classification table. The classifier that produces these classes is
// owned upstream (fizeau-44e98499); ddx consumes the class and maps it to
// exactly one FailureAction via ClassifyFailureAction. Keeping a single typed
// table on the ddx side prevents drain-loop dispositions from drifting between
// call sites and keeps ddx aligned with the shared classifier rather than
// re-deriving outcome semantics ad hoc.
type OutcomeClass string

const (
	// OutcomeClassSuccess — the attempt landed and verified work.
	OutcomeClassSuccess OutcomeClass = "success"
	// OutcomeClassAlreadySatisfied — the bead was verified as already done.
	OutcomeClassAlreadySatisfied OutcomeClass = "already_satisfied"
	// OutcomeClassNoChanges — the agent produced no changes (close/unclaim, no
	// tier escalation; a smarter model cannot manufacture work that isn't there).
	OutcomeClassNoChanges OutcomeClass = "no_changes"
	// OutcomeClassGenuineFailure — a genuine implementation/capability failure
	// (test/build/post-run-check/review failure) where a stronger model could
	// plausibly succeed. This is the ONLY class that escalates a tier.
	OutcomeClassGenuineFailure OutcomeClass = "genuine_failure"
	// OutcomeClassDirty — the worktree/index was left dirty or contended;
	// clean and retry at the same tier.
	OutcomeClassDirty OutcomeClass = "dirty"
	// OutcomeClassTransport — a transport/connectivity/routing failure; reroute
	// at the same tier (the model never got a fair attempt).
	OutcomeClassTransport OutcomeClass = "transport"
	// OutcomeClassQuotaExhausted — the provider pool is quota/rate exhausted;
	// the whole pool cools down once rather than mutating every in-flight bead.
	OutcomeClassQuotaExhausted OutcomeClass = "quota_exhausted"
	// OutcomeClassAuthSetup — an auth/setup/configuration failure that requires
	// an operator (bad key, missing harness binary, unsatisfiable pin).
	OutcomeClassAuthSetup OutcomeClass = "auth_setup"
	// OutcomeClassTimeout — the attempt timed out; clean and retry, then escalate
	// to operator attention if it times out again.
	OutcomeClassTimeout OutcomeClass = "timeout"
	// OutcomeClassMergeConflict — landing hit a merge conflict; unclaim and retry.
	OutcomeClassMergeConflict OutcomeClass = "merge_conflict"
)

// FailureAction is the single drain-loop action ddx takes for a classified
// attempt outcome, per the FEAT-004 addendum failure-classification table.
type FailureAction string

const (
	// FailureActionClose closes the bead (success / already_satisfied).
	FailureActionClose FailureAction = "close"
	// FailureActionCloseUnclaim closes/unclaims without tier escalation (no_changes).
	FailureActionCloseUnclaim FailureAction = "close_unclaim"
	// FailureActionEscalateTier retries the bead once at the next (max) tier.
	// Only ever returned for a genuine failure observed below the max tier.
	FailureActionEscalateTier FailureAction = "escalate_tier"
	// FailureActionCleanRetrySameTier cleans the worktree and retries at the
	// same tier (dirty).
	FailureActionCleanRetrySameTier FailureAction = "clean_retry_same_tier"
	// FailureActionRerouteSameTier reroutes to another provider at the same tier
	// (transport).
	FailureActionRerouteSameTier FailureAction = "reroute_same_tier"
	// FailureActionGlobalPoolCooldown cools down the whole provider pool once
	// (quota_exhausted).
	FailureActionGlobalPoolCooldown FailureAction = "global_pool_cooldown"
	// FailureActionOperatorAttention parks the bead for an operator
	// (auth/setup, or a genuine failure already at the max tier).
	FailureActionOperatorAttention FailureAction = "operator_attention"
	// FailureActionCleanRetryThenOperator cleans and retries on the first
	// timeout, then parks for an operator on a repeat timeout.
	FailureActionCleanRetryThenOperator FailureAction = "clean_retry_then_operator"
	// FailureActionUnclaimRetry unclaims and retries (merge_conflict).
	FailureActionUnclaimRetry FailureAction = "unclaim_retry"
)

// ExecutionTier is the abstract power tier an attempt ran at. ddx owns exactly
// ONE middle->max escalation (per the escalation-owner decision,
// fizeau-994604ec): a genuine failure at the middle tier escalates to max once;
// a genuine failure already at the max tier goes to operator attention instead
// of escalating again. The tier reasons in abstract middle/max terms only — it
// never names a provider, model, or harness.
type ExecutionTier string

const (
	// ExecutionTierMiddle is the default/standard execution tier.
	ExecutionTierMiddle ExecutionTier = "middle"
	// ExecutionTierMax is the top execution tier; no tier exists above it.
	ExecutionTierMax ExecutionTier = "max"
)

// ClassifyFailureAction maps one outcome class plus the tier the attempt ran at
// to exactly the action named in the FEAT-004 addendum table. It is pure: no
// I/O, no global state, no clock. The mapping is the single source of truth for
// drain-loop disposition.
//
// Escalation rule: a genuine implementation/capability failure escalates the
// tier exactly once (middle->max). At the max tier the same failure parks for
// operator attention — there is no tier above max, so re-escalation is
// impossible. No other class ever escalates a tier.
func ClassifyFailureAction(class OutcomeClass, tier ExecutionTier) FailureAction {
	switch class {
	case OutcomeClassSuccess, OutcomeClassAlreadySatisfied:
		return FailureActionClose
	case OutcomeClassNoChanges:
		return FailureActionCloseUnclaim
	case OutcomeClassGenuineFailure:
		if tier == ExecutionTierMax {
			return FailureActionOperatorAttention
		}
		return FailureActionEscalateTier
	case OutcomeClassDirty:
		return FailureActionCleanRetrySameTier
	case OutcomeClassTransport:
		return FailureActionRerouteSameTier
	case OutcomeClassQuotaExhausted:
		return FailureActionGlobalPoolCooldown
	case OutcomeClassAuthSetup:
		return FailureActionOperatorAttention
	case OutcomeClassTimeout:
		return FailureActionCleanRetryThenOperator
	case OutcomeClassMergeConflict:
		return FailureActionUnclaimRetry
	default:
		// An unknown class is never silently retried/escalated; an operator
		// inspects it. This fails safe rather than burning escalation budget on
		// an outcome the shared table did not enumerate.
		return FailureActionOperatorAttention
	}
}

// FailureActionEscalatesTier reports whether an action moves the attempt to a
// higher power tier. Only FailureActionEscalateTier does. Used by guards that
// assert no_changes/dirty/transport/quota/auth never trigger tier escalation.
func FailureActionEscalatesTier(action FailureAction) bool {
	return action == FailureActionEscalateTier
}

// OutcomeClassForReport derives the shared-table OutcomeClass from a ddx
// attempt's status, machine-readable outcome reason, failure mode, and raw
// error text. It bridges ddx's existing classification vocabulary
// (ExecuteBeadStatus*, OutcomeReason, FailureMode*) into the single shared
// table so the drain loop applies one disposition contract regardless of which
// upstream signal fired.
//
// Detection order is deliberate: quota wins over auth (a 429/quota signal is
// pool cooldown, not an operator key problem), timeout/transport win over
// generic genuine-failure buckets, and structural genuine failures are the
// fallback for real implementation/capability failures.
func OutcomeClassForReport(status, outcomeReason, failureMode, errMsg string) OutcomeClass {
	switch status {
	case ExecuteBeadStatusSuccess:
		return OutcomeClassSuccess
	case ExecuteBeadStatusAlreadySatisfied:
		return OutcomeClassAlreadySatisfied
	case ExecuteBeadStatusNoChanges:
		return OutcomeClassNoChanges
	case ExecuteBeadStatusLandConflict,
		ExecuteBeadStatusLandConflictUnresolvable:
		return OutcomeClassMergeConflict
	}

	reason := strings.ToLower(strings.TrimSpace(outcomeReason))
	mode := strings.ToLower(strings.TrimSpace(failureMode))
	lowErr := strings.ToLower(errMsg)

	// Quota exhaustion is pool-wide and must be detected before auth so a
	// 429/quota signal cools the pool rather than parking for an operator.
	if reason == ReadinessSystemReasonQuota ||
		containsAny(lowErr, "quota exceeded", "insufficient quota", "insufficient_quota", "usage ceiling", "spend cap") {
		return OutcomeClassQuotaExhausted
	}

	switch reason {
	case ReadinessSystemReasonTransport, ReadinessSystemReasonRouting:
		return OutcomeClassTransport
	case ReadinessSystemReasonTimeout:
		return OutcomeClassTimeout
	case "merge_conflict":
		return OutcomeClassMergeConflict
	}

	switch mode {
	case FailureModeMergeConflict:
		return OutcomeClassMergeConflict
	case FailureModeTimeout,
		FailureModeRouteResolutionTimeout,
		FailureModeProgressWatchdog:
		return OutcomeClassTimeout
	case FailureModeProviderConnectivity,
		FailureModeNoViableProvider:
		return OutcomeClassTransport
	case FailureModeAuthError,
		FailureModeHarnessNotInstalled,
		FailureModeBlockedByPassthroughConstraint,
		FailureModeAgentPowerUnsatisfied:
		return OutcomeClassAuthSetup
	case FailureModeLockContention,
		FailureModeAttemptIntegrity:
		return OutcomeClassDirty
	}

	// Dirty worktree/index left behind by an interrupted attempt: clean + retry.
	if containsAny(lowErr, "index.lock", "uncommitted changes", "working tree is dirty", "working tree dirty") {
		return OutcomeClassDirty
	}

	// Everything else that reached here is a genuine implementation/capability
	// failure (test/build/post-run-check/review failure, execution_failed).
	return OutcomeClassGenuineFailure
}

// MaxAttemptPool enforces a per-pool in-flight cap on max-tier attempts so a
// fleet of workers all escalating to the max tier at once cannot stampede a
// single provider pool. A "pool" is an abstract provider group keyed by a
// caller-supplied string (e.g. the max-tier pool name). The cap is the maximum
// number of attempts that may be in flight against one pool concurrently.
//
// MaxAttemptPool is safe for concurrent use across workers.
type MaxAttemptPool struct {
	max      int
	mu       sync.Mutex
	inFlight map[string]int
}

// NewMaxAttemptPool constructs a cap allowing at most max concurrent in-flight
// attempts per pool. A max <= 0 disables the cap (TryAcquire always succeeds).
func NewMaxAttemptPool(max int) *MaxAttemptPool {
	return &MaxAttemptPool{max: max, inFlight: map[string]int{}}
}

// TryAcquire reserves an in-flight slot for pool. It returns true when a slot
// was reserved (the caller MUST call Release when the attempt finishes) and
// false when the pool is already at its cap. When the cap is disabled it always
// returns true without tracking.
func (p *MaxAttemptPool) TryAcquire(pool string) bool {
	if p == nil || p.max <= 0 {
		return true
	}
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.inFlight[pool] >= p.max {
		return false
	}
	p.inFlight[pool]++
	return true
}

// Release frees a previously acquired in-flight slot for pool. Releasing a pool
// with no in-flight slots is a no-op so a double Release cannot drive the
// counter negative.
func (p *MaxAttemptPool) Release(pool string) {
	if p == nil || p.max <= 0 {
		return
	}
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.inFlight[pool] > 0 {
		p.inFlight[pool]--
		if p.inFlight[pool] == 0 {
			delete(p.inFlight, pool)
		}
	}
}

// InFlight reports the current number of in-flight slots reserved for pool.
func (p *MaxAttemptPool) InFlight(pool string) int {
	if p == nil {
		return 0
	}
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.inFlight[pool]
}

// PoolQuotaCooldown records quota-exhaustion cooldowns at the provider-pool
// level. When many in-flight beads observe quota exhaustion at once, the pool
// is cooled down ONCE rather than writing a per-bead retry-after on every
// affected bead (FEAT-004 addendum: quota-exhausted -> global pool cooldown,
// not N per-bead mutations; aligns with TD-031 §7.3 QuotaPauseContract, which
// keeps quota a worker/pool-state concern with no per-bead status change).
//
// PoolQuotaCooldown is safe for concurrent use across workers.
type PoolQuotaCooldown struct {
	mu        sync.Mutex
	until     map[string]time.Time
	mutations int
}

// NewPoolQuotaCooldown constructs an empty pool-cooldown tracker.
func NewPoolQuotaCooldown() *PoolQuotaCooldown {
	return &PoolQuotaCooldown{until: map[string]time.Time{}}
}

// EnterCooldown puts pool into cooldown until the given time. It is idempotent
// within an active window: while a cooldown is already active for pool (now is
// before the recorded until), repeated calls do NOT write again, so N beads
// observing the same quota exhaustion produce exactly one global mutation.
// EnterCooldown returns true only on the call that actually entered (or
// extended past) the cooldown, i.e. the call that mutated global state.
func (c *PoolQuotaCooldown) EnterCooldown(pool string, now, until time.Time) bool {
	if c == nil {
		return false
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	if existing, ok := c.until[pool]; ok && now.Before(existing) && !until.After(existing) {
		// A cooldown is already active and the new request would not extend it:
		// fold this observation into the existing global cooldown.
		return false
	}
	c.until[pool] = until
	c.mutations++
	return true
}

// Active reports whether pool is currently cooling down (now is before the
// recorded until).
func (c *PoolQuotaCooldown) Active(pool string, now time.Time) bool {
	if c == nil {
		return false
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	until, ok := c.until[pool]
	return ok && now.Before(until)
}

// Mutations returns the total number of cooldown writes performed across all
// pools. Used to assert that a burst of quota observations collapses into a
// single global mutation rather than one mutation per bead.
func (c *PoolQuotaCooldown) Mutations() int {
	if c == nil {
		return 0
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.mutations
}

package agent

import (
	"sync"
	"sync/atomic"
	"testing"
	"time"
)

// TestClassifyFailureAction_AddendumTable is the table-driven proof that ddx
// maps each shared-classifier outcome class to exactly the action named in the
// FEAT-004 addendum failure-classification table (AC #1).
func TestClassifyFailureAction_AddendumTable(t *testing.T) {
	cases := []struct {
		name  string
		class OutcomeClass
		tier  ExecutionTier
		want  FailureAction
	}{
		{"success closes", OutcomeClassSuccess, ExecutionTierMiddle, FailureActionClose},
		{"already_satisfied closes", OutcomeClassAlreadySatisfied, ExecutionTierMiddle, FailureActionClose},
		{"no_changes close/unclaim", OutcomeClassNoChanges, ExecutionTierMiddle, FailureActionCloseUnclaim},
		{"genuine failure at middle escalates", OutcomeClassGenuineFailure, ExecutionTierMiddle, FailureActionEscalateTier},
		{"genuine failure at max -> operator", OutcomeClassGenuineFailure, ExecutionTierMax, FailureActionOperatorAttention},
		{"dirty clean+same-tier retry", OutcomeClassDirty, ExecutionTierMiddle, FailureActionCleanRetrySameTier},
		{"transport same-tier reroute", OutcomeClassTransport, ExecutionTierMiddle, FailureActionRerouteSameTier},
		{"quota -> global pool cooldown", OutcomeClassQuotaExhausted, ExecutionTierMiddle, FailureActionGlobalPoolCooldown},
		{"auth/setup -> operator", OutcomeClassAuthSetup, ExecutionTierMiddle, FailureActionOperatorAttention},
		{"timeout clean+retry then operator", OutcomeClassTimeout, ExecutionTierMiddle, FailureActionCleanRetryThenOperator},
		{"merge_conflict unclaim+retry", OutcomeClassMergeConflict, ExecutionTierMiddle, FailureActionUnclaimRetry},
		{"unknown class fails safe to operator", OutcomeClass("bogus"), ExecutionTierMiddle, FailureActionOperatorAttention},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if got := ClassifyFailureAction(tc.class, tc.tier); got != tc.want {
				t.Fatalf("ClassifyFailureAction(%q, %q) = %q, want %q", tc.class, tc.tier, got, tc.want)
			}
		})
	}
}

// TestClassifyFailureAction_SingleMiddleToMaxEscalation proves AC #2: exactly
// one middle->max escalation, only on a typed genuine failure, and that
// no_changes/dirty/transport/quota/auth never escalate a tier at either tier.
func TestClassifyFailureAction_SingleMiddleToMaxEscalation(t *testing.T) {
	// Genuine failure is the ONLY class that escalates, and only from middle.
	if got := ClassifyFailureAction(OutcomeClassGenuineFailure, ExecutionTierMiddle); !FailureActionEscalatesTier(got) {
		t.Fatalf("genuine failure at middle must escalate; got %q", got)
	}
	// At max there is no higher tier: the same failure parks for an operator,
	// so escalation happens at most ONCE on the middle->max hop.
	if got := ClassifyFailureAction(OutcomeClassGenuineFailure, ExecutionTierMax); FailureActionEscalatesTier(got) {
		t.Fatalf("genuine failure at max must NOT escalate again; got %q", got)
	} else if got != FailureActionOperatorAttention {
		t.Fatalf("genuine failure at max = %q, want operator_attention", got)
	}

	nonEscalating := []OutcomeClass{
		OutcomeClassNoChanges,
		OutcomeClassDirty,
		OutcomeClassTransport,
		OutcomeClassQuotaExhausted,
		OutcomeClassAuthSetup,
		OutcomeClassSuccess,
		OutcomeClassAlreadySatisfied,
		OutcomeClassTimeout,
		OutcomeClassMergeConflict,
	}
	for _, class := range nonEscalating {
		for _, tier := range []ExecutionTier{ExecutionTierMiddle, ExecutionTierMax} {
			if got := ClassifyFailureAction(class, tier); FailureActionEscalatesTier(got) {
				t.Fatalf("class %q at tier %q escalated (%q); only genuine_failure may escalate", class, tier, got)
			}
		}
	}
}

// TestOutcomeClassForReport bridges ddx's existing status/reason/failure-mode
// vocabulary into the shared table.
func TestOutcomeClassForReport(t *testing.T) {
	cases := []struct {
		name    string
		status  string
		reason  string
		mode    string
		errMsg  string
		want    OutcomeClass
	}{
		{"success status", ExecuteBeadStatusSuccess, "", "", "", OutcomeClassSuccess},
		{"already satisfied status", ExecuteBeadStatusAlreadySatisfied, "", "", "", OutcomeClassAlreadySatisfied},
		{"no changes status", ExecuteBeadStatusNoChanges, "", "", "", OutcomeClassNoChanges},
		{"land conflict status", ExecuteBeadStatusLandConflict, "", "", "", OutcomeClassMergeConflict},
		{"quota reason beats auth", "", ReadinessSystemReasonQuota, FailureModeAuthError, "", OutcomeClassQuotaExhausted},
		{"quota error text", ExecuteBeadStatusExecutionFailed, "", "", "openai: insufficient quota", OutcomeClassQuotaExhausted},
		{"transport reason", "", ReadinessSystemReasonTransport, "", "", OutcomeClassTransport},
		{"routing reason -> transport", "", ReadinessSystemReasonRouting, "", "", OutcomeClassTransport},
		{"timeout reason", "", ReadinessSystemReasonTimeout, "", "", OutcomeClassTimeout},
		{"timeout mode", ExecuteBeadStatusExecutionFailed, "", FailureModeTimeout, "", OutcomeClassTimeout},
		{"provider connectivity mode -> transport", ExecuteBeadStatusExecutionFailed, "", FailureModeProviderConnectivity, "", OutcomeClassTransport},
		{"auth mode", ExecuteBeadStatusExecutionFailed, "", FailureModeAuthError, "", OutcomeClassAuthSetup},
		{"harness-not-installed -> auth/setup", ExecuteBeadStatusExecutionFailed, "", FailureModeHarnessNotInstalled, "", OutcomeClassAuthSetup},
		{"attempt integrity -> dirty", ExecuteBeadStatusPreservedNeedsReview, "", FailureModeAttemptIntegrity, "", OutcomeClassDirty},
		{"index lock text -> dirty", ExecuteBeadStatusExecutionFailed, "", "", "fatal: Unable to create '.git/index.lock'", OutcomeClassDirty},
		{"merge mode", ExecuteBeadStatusPostRunCheckFailed, "", FailureModeMergeConflict, "", OutcomeClassMergeConflict},
		{"plain execution failure -> genuine", ExecuteBeadStatusExecutionFailed, "", FailureModeTestFailure, "tests failed", OutcomeClassGenuineFailure},
		{"post-run check -> genuine", ExecuteBeadStatusPostRunCheckFailed, "", "", "", OutcomeClassGenuineFailure},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if got := OutcomeClassForReport(tc.status, tc.reason, tc.mode, tc.errMsg); got != tc.want {
				t.Fatalf("OutcomeClassForReport(%q,%q,%q,%q) = %q, want %q",
					tc.status, tc.reason, tc.mode, tc.errMsg, got, tc.want)
			}
		})
	}
}

// TestMaxAttemptPool_CapEnforced proves AC #3: a per-pool in-flight cap bounds
// the number of concurrent max-tier escalations, preventing a multi-worker
// stampede. Many workers hit a genuine failure at the same instant and try to
// escalate into the same pool; at most `cap` may hold a slot concurrently.
func TestMaxAttemptPool_CapEnforced(t *testing.T) {
	const (
		cap     = 3
		workers = 50
		pool    = "max-tier"
	)
	p := NewMaxAttemptPool(cap)

	var (
		acquired   int64
		concurrent int64
		peak       int64
		release    = make(chan struct{})
		ready      sync.WaitGroup
		done       sync.WaitGroup
	)
	ready.Add(workers)
	done.Add(workers)
	for i := 0; i < workers; i++ {
		go func() {
			defer done.Done()
			// Each worker just observed a genuine failure and asks ClassifyFailureAction
			// for the disposition; only escalations contend for the pool.
			if action := ClassifyFailureAction(OutcomeClassGenuineFailure, ExecutionTierMiddle); action != FailureActionEscalateTier {
				ready.Done()
				return
			}
			if !p.TryAcquire(pool) {
				ready.Done()
				return
			}
			atomic.AddInt64(&acquired, 1)
			cur := atomic.AddInt64(&concurrent, 1)
			for {
				old := atomic.LoadInt64(&peak)
				if cur <= old || atomic.CompareAndSwapInt64(&peak, old, cur) {
					break
				}
			}
			ready.Done()
			<-release // hold the slot until every worker has tried to acquire
			atomic.AddInt64(&concurrent, -1)
			p.Release(pool)
		}()
	}

	ready.Wait()
	if got := atomic.LoadInt64(&peak); got > cap {
		t.Fatalf("peak concurrent in-flight = %d, exceeds cap %d", got, cap)
	}
	if got := p.InFlight(pool); got > cap {
		t.Fatalf("InFlight = %d, exceeds cap %d", got, cap)
	}
	if got := atomic.LoadInt64(&acquired); got != cap {
		t.Fatalf("acquired = %d, want exactly cap %d while slots are held", got, cap)
	}
	close(release)
	done.Wait()

	// Slots are returned after release; the pool drains to zero.
	if got := p.InFlight(pool); got != 0 {
		t.Fatalf("InFlight after release = %d, want 0", got)
	}

	// A different pool is independent of a saturated one.
	p2 := NewMaxAttemptPool(1)
	if !p2.TryAcquire("a") || !p2.TryAcquire("b") {
		t.Fatal("independent pools must not share the cap")
	}
	if p2.TryAcquire("a") {
		t.Fatal("second acquire on a cap-1 pool must fail")
	}
}

// TestPoolQuotaCooldown_GlobalNotPerBead proves AC #4: when N in-flight beads
// observe quota exhaustion, the provider pool cools down with a single global
// mutation rather than N per-bead mutations.
func TestPoolQuotaCooldown_GlobalNotPerBead(t *testing.T) {
	const (
		beads = 25
		pool  = "billed-pool"
	)
	now := time.Unix(1_700_000_000, 0).UTC()
	until := now.Add(15 * time.Minute)
	c := NewPoolQuotaCooldown()

	entered := 0
	for i := 0; i < beads; i++ {
		// Every bead classifies quota -> global pool cooldown, then folds its
		// observation into the one pool cooldown.
		if action := ClassifyFailureAction(OutcomeClassQuotaExhausted, ExecutionTierMiddle); action != FailureActionGlobalPoolCooldown {
			t.Fatalf("quota must map to global pool cooldown; got %q", action)
		}
		if c.EnterCooldown(pool, now, until) {
			entered++
		}
	}

	if entered != 1 {
		t.Fatalf("EnterCooldown reported %d entries across %d beads, want exactly 1 global entry", entered, beads)
	}
	if got := c.Mutations(); got != 1 {
		t.Fatalf("pool cooldown mutations = %d across %d quota observations, want 1 (not N per-bead)", got, beads)
	}
	if !c.Active(pool, now) {
		t.Fatal("pool must be in cooldown after quota exhaustion")
	}
	if c.Active(pool, until.Add(time.Second)) {
		t.Fatal("pool cooldown must expire after the window")
	}

	// A genuinely longer cooldown observed later extends the window (one more mutation).
	if !c.EnterCooldown(pool, now, until.Add(time.Hour)) {
		t.Fatal("a longer cooldown should extend the window")
	}
	if got := c.Mutations(); got != 2 {
		t.Fatalf("mutations after extend = %d, want 2", got)
	}
}

